import React from 'react';

interface CardProps {
  children: React.ReactNode;
  className?: string;
  title?: string;
  action?: React.ReactNode;
}

export const Card: React.FC<CardProps> = ({ children, className = '', title, action }) => {
  return (
    <div className={`bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col ${className}`}>
      {(title || action) && (
        <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50/50 shrink-0">
          {title && <h3 className="font-semibold text-gray-800">{title}</h3>}
          {action && <div>{action}</div>}
        </div>
      )}
      <div className="p-6 flex-1 min-h-0 flex flex-col">
        {children}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Trash2, ArrowDownCircle, ArrowUpCircle, CreditCard, Edit2, Filter } from 'lucide-react';
import { Transaction } from '../types';

interface Props {
  transactions: Transaction[];
  onDelete: (id: string) => void;
  onEdit: (transaction: Transaction) => void;
  currentViewDate: Date;
}

export const TransactionList: React.FC<Props> = ({ transactions, onDelete, onEdit, currentViewDate }) => {
  const [selectedYear, setSelectedYear] = useState<number>(currentViewDate.getFullYear());
  const [selectedMonth, setSelectedMonth] = useState<number>(currentViewDate.getMonth() + 1);

  // Sync internal state when the dashboard's currentViewDate changes
  useEffect(() => {
    setSelectedYear(currentViewDate.getFullYear());
    setSelectedMonth(currentViewDate.getMonth() + 1);
  }, [currentViewDate]);

  // Extract available years from transactions for the dropdown
  const availableYears = useMemo(() => {
    const years = new Set([new Date().getFullYear()]);
    transactions.forEach(t => {
      years.add(new Date(t.date).getFullYear());
    });
    return Array.from(years).sort((a, b) => b - a);
  }, [transactions]);

  // Filter transactions based on selection
  const filteredAndSortedTransactions = useMemo(() => {
    return transactions
      .filter(t => {
        const d = new Date(t.date);
        return d.getFullYear() === selectedYear && (d.getMonth() + 1) === selectedMonth;
      })
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, selectedYear, selectedMonth]);

  const totalIncome = filteredAndSortedTransactions
    .filter(t => t.type === 'income')
    .reduce((sum, t) => sum + t.amount, 0);

  const totalExpense = filteredAndSortedTransactions
    .filter(t => t.type === 'expense')
    .reduce((sum, t) => sum + t.amount, 0);

  return (
    <div className="flex flex-col">
      {/* Filter Bar - Sticky Top */}
      <div className="sticky top-0 bg-white z-20 pb-2 border-b border-gray-100 mb-2 space-y-2">
        <div className="flex items-center justify-between gap-2">
          <div className="flex items-center gap-2">
            <div className="relative">
              <select
                value={selectedYear}
                onChange={(e) => setSelectedYear(Number(e.target.value))}
                className="appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-20 p-2 pr-6 outline-none font-medium cursor-pointer"
              >
                {availableYears.map(year => (
                  <option key={year} value={year}>{year}년</option>
                ))}
              </select>
            </div>
            <div className="relative">
              <select
                value={selectedMonth}
                onChange={(e) => setSelectedMonth(Number(e.target.value))}
                className="appearance-none bg-gray-50 border border-gray-200 text-gray-700 text-sm rounded-lg focus:ring-indigo-500 focus:border-indigo-500 block w-16 p-2 pr-6 outline-none font-medium cursor-pointer"
              >
                {Array.from({ length: 12 }, (_, i) => i + 1).map(month => (
                  <option key={month} value={month}>{month}월</option>
                ))}
              </select>
            </div>
          </div>
          <div className="text-right">
             <span className="text-xs text-gray-500 font-medium block">내역 {filteredAndSortedTransactions.length}건</span>
          </div>
        </div>

        {/* Mini Summary for the filtered list */}
        <div className="flex gap-2 text-xs">
           <div className="px-2 py-1 bg-blue-50 text-blue-600 rounded-md font-medium">
             수입: {totalIncome.toLocaleString()}
           </div>
           <div className="px-2 py-1 bg-red-50 text-red-600 rounded-md font-medium">
             지출: {totalExpense.toLocaleString()}
           </div>
        </div>
      </div>

      {/* List Content */}
      <div className="space-y-3 pt-2">
        {filteredAndSortedTransactions.length === 0 ? (
          <div className="text-center py-12 text-gray-400 text-sm flex flex-col items-center gap-2">
            <Filter size={24} className="opacity-20" />
            <p>해당 기간의 거래 내역이 없습니다.</p>
          </div>
        ) : (
          filteredAndSortedTransactions.map((t) => (
            <div key={t.id} className="group flex items-center justify-between p-3 hover:bg-gray-50 rounded-lg transition-colors border border-transparent hover:border-gray-100 relative">
              <div className="flex items-center gap-3">
                <div className={`${t.type === 'income' ? 'text-blue-500' : 'text-red-500'} shrink-0`}>
                  {t.type === 'income' ? <ArrowUpCircle size={24} /> : <ArrowDownCircle size={24} />}
                </div>
                <div>
                  <div className="flex items-center gap-2 flex-wrap">
                    <p className="font-medium text-gray-800 text-sm">{t.category}</p>
                    {t.bank && (
                      <span className="text-[10px] px-1.5 py-0.5 bg-gray-100 text-gray-500 rounded-md flex items-center gap-1 shrink-0">
                        <CreditCard size={10} />
                        {t.bank}
                      </span>
                    )}
                  </div>
                  <p className="text-xs text-gray-500 mt-0.5">
                    {t.date} {t.description && `• ${t.description}`}
                  </p>
                </div>
              </div>
              <div className="flex items-center gap-3 shrink-0">
                <span className={`font-semibold text-sm ${t.type === 'income' ? 'text-blue-600' : 'text-red-600'}`}>
                  {t.type === 'income' ? '+' : '-'}{t.amount.toLocaleString()}원
                </span>

                {/* Action Buttons with High Z-Index and Click Area */}
                <div className="flex items-center gap-1 z-10 relative">
                  <button 
                    type="button"
                    onClick={(e) => { 
                      e.stopPropagation(); 
                      onEdit(t); 
                    }}
                    className="p-2 text-gray-400 hover:text-indigo-500 hover:bg-indigo-50 rounded-full transition-colors cursor-pointer"
                    title="수정"
                  >
                    <Edit2 size={16} />
                  </button>
                  <button 
                    type="button"
                    onClick={(e) => { 
                      e.stopPropagation(); 
                      onDelete(t.id); 
                    }}
                    className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors cursor-pointer"
                    title="삭제"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

