const App = () => {
  // --- State ---
  const [currentDate, setCurrentDate] = useState(new Date());
  const [isStorageReady, setIsStorageReady] = useState(false);
  const [isPersistent, setIsPersistent] = useState(false);

  // PWA Install Prompt State
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isInstallGuideOpen, setIsInstallGuideOpen] = useState(false);

  // Transactions with Migration Logic
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const parseData = (jsonStr: string | null) => {
        if (!jsonStr) return null;
        try {
            const parsed = JSON.parse(jsonStr);
            if (Array.isArray(parsed)) {
                return parsed.map((t: any) => ({
                    ...t,
                    id: t.id || Math.random().toString(36).substr(2, 9),
                    bank: t.bank || '기타',
                    description: t.description || '' 
                }));
            }
        } catch (e) { console.error("Data Parse Error:", e); }
        return null;
    };

    const mainData = parseData(localStorage.getItem('moneyflow_transactions'));
    if (mainData) return mainData;
    const backupData = parseData(localStorage.getItem('moneyflow_transactions_safety_backup'));
    if (backupData && backupData.length > 0) return backupData;
    return [];
  });

  useEffect(() => {
      setIsStorageReady(true);
      if (navigator.storage && navigator.storage.persist) {
        navigator.storage.persist().then(granted => setIsPersistent(granted));
      }
      const handleBeforeInstallPrompt = (e: any) => {
        e.preventDefault();
        setDeferredPrompt(e);
      };
      window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
      return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  const [investmentRecords, setInvestmentRecords] = useState<InvestmentRecord[]>(() => {
    try {
        const saved = localStorage.getItem('moneyflow_investments');
        return saved ? JSON.parse(saved) : [];
    } catch(e) { return []; }
  });

  const [recurringExpenses, setRecurringExpenses] = useState<RecurringExpense[]>(() => {
      try {
          const saved = localStorage.getItem('moneyflow_recurring_bills');
          return saved ? JSON.parse(saved) : [];
      } catch(e) { return []; }
  });

  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);

  const [expenseCats, setExpenseCats] = useState<string[]>(() => {
    const saved = localStorage.getItem('moneyflow_expense_categories_v3');
    return saved ? JSON.parse(saved) : EXPENSE_CATEGORIES;
  });

  const [incomeCats, setIncomeCats] = useState<string[]>(() => {
    const saved = localStorage.getItem('moneyflow_income_categories_v3');
    return saved ? JSON.parse(saved) : INCOME_CATEGORIES;
  });

  const [budgets, setBudgets] = useState<BudgetMap>(() => {
      const saved = localStorage.getItem('moneyflow_budgets');
      return saved ? JSON.parse(saved) : {};
  });

  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [isDataModalOpen, setIsDataModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [toast, setToast] = useState<{ msg: string; type?: 'success'|'error'|'info' } | null>(null);
  const [confirmDialog, setConfirmDialog] = useState<{ isOpen: boolean; message: string; onConfirm: () => void }>({
    isOpen: false, message: '', onConfirm: () => {},
  });
  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);

  // --- Persistence ---
  useEffect(() => {
    if (!isStorageReady) return;
    localStorage.setItem('moneyflow_transactions', JSON.stringify(transactions));
    if (transactions.length > 0) localStorage.setItem('moneyflow_transactions_safety_backup', JSON.stringify(transactions));
  }, [transactions, isStorageReady]);

  useEffect(() => {
    if (!isStorageReady) return;
    localStorage.setItem('moneyflow_investments', JSON.stringify(investmentRecords));
  }, [investmentRecords, isStorageReady]);

  useEffect(() => {
      if (!isStorageReady) return;
      localStorage.setItem('moneyflow_recurring_bills', JSON.stringify(recurringExpenses));
  }, [recurringExpenses, isStorageReady]);

  useEffect(() => {
    localStorage.setItem('moneyflow_expense_categories_v3', JSON.stringify(expenseCats));
  }, [expenseCats]);

  useEffect(() => {
    localStorage.setItem('moneyflow_income_categories_v3', JSON.stringify(incomeCats));
  }, [incomeCats]);

  useEffect(() => {
      localStorage.setItem('moneyflow_budgets', JSON.stringify(budgets));
  }, [budgets]);

  // --- Helpers ---
  const getMonthStr = (d: Date) => {
    const offset = d.getTimezoneOffset() * 60000;
    return new Date(d.getTime() - offset).toISOString().slice(0, 7);
  };

  const currentMonthStr = getMonthStr(currentDate);
  const currentYear = currentDate.getFullYear();

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => t.date.startsWith(currentMonthStr));
  }, [transactions, currentMonthStr]);

  const stats: MonthlyStats = useMemo(() => {
    return filteredTransactions.reduce((acc, curr) => {
      if (curr.type === 'income') {
        acc.totalIncome += curr.amount;
        acc.balance += curr.amount;
      } else {
        acc.totalExpense += curr.amount;
        acc.balance -= curr.amount;
      }
      return acc;
    }, { totalIncome: 0, totalExpense: 0, balance: 0 });
  }, [filteredTransactions]);

  const showToast = (msg: string, type: 'success'|'error'|'info' = 'success') => setToast({ msg, type });

  // --- Handlers ---
  const handleAddTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const tx: Transaction = { ...newTx, id: Math.random().toString(36).substr(2, 9) };
    setTransactions(prev => [...prev, tx]);
    showToast('내역이 추가되었습니다.');
  };

  const handleEditTransaction = (tx: Transaction) => {
    setEditingTransaction(tx);
    document.getElementById('transaction-form-section')?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleUpdateTransaction = (updatedTx: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updatedTx.id ? updatedTx : t));
    setEditingTransaction(null);
    showToast('내역이 수정되었습니다.');
  };

  const handleDeleteTransaction = (id: string) => {
    setConfirmDialog({
        isOpen: true,
        message: '이 거래 내역을 삭제하시겠습니까?',
        onConfirm: () => {
            setTransactions(prev => prev.filter(t => t.id !== id));
            showToast('내역이 삭제되었습니다.');
        }
    });
  };

  const handleAnalyze = async () => {
    const yearTransactions = transactions.filter(t => new Date(t.date).getFullYear() === currentYear);
    if (yearTransactions.length === 0) {
      showToast('분석할 연간 데이터가 없습니다.', 'error');
      return;
    }
    setIsAnalyzing(true);
    setShowAnalysis(true);
    const result = await analyzeFinancialData(yearTransactions, `${currentYear}년 ${currentDate.getMonth() + 1}월`);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  const handleImportData = (importedData: any) => {
    setConfirmDialog({
        isOpen: true,
        message: '데이터를 복구하시겠습니까? 기존 데이터가 덮어씌워질 수 있습니다.',
        onConfirm: () => {
            if (importedData.transactions) setTransactions(importedData.transactions);
            else if (Array.isArray(importedData)) setTransactions(importedData);
            showToast('복구가 완료되었습니다.');
        }
    });
  };

  return (
    <div className="min-h-screen pb-12 bg-gray-50 select-none sm:select-text">
      <header className="bg-gradient-to-r from-indigo-700 to-purple-800 text-white pb-24 pt-8 px-4 shadow-xl">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
          <div className="flex items-center gap-3">
            <div className="p-2 bg-white/10 backdrop-blur-sm rounded-xl"><Wallet size={28} /></div>
            <div>
              <h1 className="text-2xl font-bold tracking-tight">MoneyFlow AI</h1>
              <p className="text-indigo-200 text-xs">스마트한 자산 관리 • {isPersistent ? '영구 저장 활성' : '브라우저 저장'}</p>
            </div>
          </div>
          <div className="flex flex-wrap gap-2 justify-center">
            <button onClick={() => setIsHistoryOpen(true)} className="flex items-center gap-2 bg-white/10 hover:bg-white/20 px-4 py-2 rounded-full text-sm font-semibold border border-white/20"><History size={18} />리포트</button>
            <button onClick={() => setIsDataModalOpen(true)} className="flex items-center gap-2 bg-white/10 hover:bg-white/20 px-4 py-2 rounded-full text-sm font-semibold border border-white/20"><Settings size={18} />데이터</button>
            <button onClick={handleAnalyze} className="group flex items-center gap-2 bg-indigo-500 hover:bg-indigo-400 px-4 py-2 rounded-full text-sm font-semibold shadow-lg border border-indigo-400/50">
              {isAnalyzing ? <Loader2 className="animate-spin" size={18} /> : <Sparkles size={18} className="text-yellow-300" />}AI 분석
            </button>
          </div>
        </div>
        <div className="max-w-7xl mx-auto flex flex-col items-center justify-center">
           <div className="flex items-center gap-8">
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} className="p-2 hover:bg-white/10 rounded-full"><ChevronLeft size={32} /></button>
            <div className="text-center">
              <div className="text-indigo-200 text-sm mb-1">{currentYear}</div>
              <h2 className="text-4xl font-bold">{currentDate.getMonth() + 1}월</h2>
            </div>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} className="p-2 hover:bg-white/10 rounded-full"><ChevronRight size={32} /></button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 -mt-16 space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-white p-6 rounded-2xl shadow-lg border border-gray-100 flex items-center gap-5">
            <div className="p-4 bg-blue-50 text-blue-600 rounded-2xl"><TrendingUp size={28} /></div>
            <div><p className="text-sm text-gray-500">수입</p><p className="text-2xl font-bold">{stats.totalIncome.toLocaleString()}원</p></div>
          </div>
          <div className="bg-white p-6 rounded-2xl shadow-lg border border-gray-100 flex items-center gap-5">
            <div className="p-4 bg-red-50 text-red-600 rounded-2xl"><TrendingDown size={28} /></div>
            <div><p className="text-sm text-gray-500">지출</p><p className="text-2xl font-bold">{stats.totalExpense.toLocaleString()}원</p></div>
          </div>
          <div className="bg-white p-6 rounded-2xl shadow-lg border border-gray-100 flex items-center gap-5">
            <div className={`p-4 rounded-2xl ${stats.balance >= 0 ? 'bg-emerald-50 text-emerald-600' : 'bg-orange-50 text-orange-600'}`}><Wallet size={28} /></div>
            <div><p className="text-sm text-gray-500">잔액</p><p className="text-2xl font-bold">{stats.balance.toLocaleString()}원</p></div>
          </div>
        </div>

        {showAnalysis && (
          <Card className="border-indigo-100 ring-4 ring-indigo-50/50 shadow-xl" title="AI 연간 재정 리포트">
            {isAnalyzing ? (
              <div className="py-12 text-center text-gray-500 flex flex-col items-center gap-4"><Loader2 className="animate-spin text-indigo-500" size={40} /><p>Gemini가 데이터를 분석하고 있습니다...</p></div>
            ) : <div className="prose prose-indigo max-w-none text-gray-700 whitespace-pre-line p-2">{aiAnalysis}</div>}
          </Card>
        )}

        <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
          <div className="xl:col-span-2 space-y-6">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
                <DashboardCharts currentMonthTransactions={filteredTransactions} />
                <YearlyChart transactions={transactions} year={currentYear} />
                <InvestmentStatus records={investmentRecords} onAddRecord={(r) => setInvestmentRecords(prev => [...prev, { ...r, id: Math.random().toString(36).substr(2, 9) }])} onDeleteRecord={(id) => setInvestmentRecords(prev => prev.filter(r => r.id !== id))} currentViewDate={currentDate} />
            </div>
            <BudgetOverview categories={expenseCats} transactions={filteredTransactions} budgets={budgets} onUpdateBudgets={setBudgets} />
          </div>

          <div className="space-y-6">
             <UpcomingBills expenses={recurringExpenses} onAdd={(e) => setRecurringExpenses(prev => [...prev, { ...e, id: Math.random().toString(36).substr(2, 9) }])} onUpdate={(u) => setRecurringExpenses(prev => prev.map(e => e.id === u.id ? u : e))} onDelete={(id) => setRecurringExpenses(prev => prev.filter(e => e.id !== id))} onPay={() => {}} currentViewDate={currentDate} transactions={transactions} categories={expenseCats} />

             <div id="transaction-form-section" className="bg-white rounded-2xl shadow-md border border-gray-100 overflow-hidden">
                <div className={`px-6 py-4 border-b border-gray-100 ${editingTransaction ? 'bg-indigo-50' : 'bg-gray-50'}`}>
                  <h3 className="font-bold text-gray-800">{editingTransaction ? '거래 내역 수정' : '거래 내역 추가'}</h3>
                </div>
                <div className="p-6">
                  <TransactionForm onAddTransaction={handleAddTransaction} onUpdateTransaction={handleUpdateTransaction} editingTransaction={editingTransaction} onCancelEdit={() => setEditingTransaction(null)} incomeCategories={incomeCats} expenseCategories={expenseCats} onOpenCategoryManager={() => setIsCategoryManagerOpen(true)} currentViewDate={currentDate} />
                </div>
             </div>

             {/* 내역 목록 카드: h-[400px] 고정 및 내부 스크롤 처리 */}
             <Card title="내역 목록" className="h-[400px] shadow-md">
                <div className="h-full overflow-y-auto custom-scrollbar">
                  <TransactionList 
                    transactions={transactions} 
                    currentViewDate={currentDate}
                    onDelete={handleDeleteTransaction}
                    onEdit={handleEditTransaction}
                  />
                </div>
             </Card>
          </div>
        </div>
      </main>

      <CategoryManager isOpen={isCategoryManagerOpen} onClose={() => setIsCategoryManagerOpen(false)} incomeCategories={incomeCats} expenseCategories={expenseCats} onUpdateCategories={(type, newCats) => type === 'income' ? setIncomeCats(newCats) : setExpenseCats(newCats)} />
      <DataManagement isOpen={isDataModalOpen} onClose={() => setIsDataModalOpen(false)} transactions={transactions} onImport={handleImportData} onEmergencyRestore={() => {}} onExport={() => {}} />
      <MonthlyHistory isOpen={isHistoryOpen} onClose={() => setIsHistoryOpen(false)} transactions={transactions} onSelectMonth={setCurrentDate} />
      <ConfirmDialog isOpen={confirmDialog.isOpen} message={confirmDialog.message} onConfirm={confirmDialog.onConfirm} onClose={() => setConfirmDialog(prev => ({ ...prev, isOpen: false }))} />
      <InstallGuide isOpen={isInstallGuideOpen} onClose={() => setIsInstallGuideOpen(false)} deferredPrompt={deferredPrompt} onInstall={() => deferredPrompt?.prompt()} />
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)} />}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e2e8f0; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #cbd5e1; }
      `}</style>
    </div>
  );
};

export default App;

import React from 'react';

interface CardProps {
  children: React.ReactNode;
  className?: string;
  title?: string;
  action?: React.ReactNode;
}

export const Card: React.FC<CardProps> = ({ children, className = '', title, action }) => {
  return (
    <div className={`bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col ${className}`}>
      {(title || action) && (
        <div className="px-5 py-3 border-b border-gray-100 flex justify-between items-center bg-gray-50/50 shrink-0">
          {title && <h3 className="font-bold text-gray-800 text-sm">{title}</h3>}
          {action && <div>{action}</div>}
