            <div className="text-center">
              <div className="text-indigo-300 text-xs font-black mb-1 uppercase tracking-tighter">{currentDate.getFullYear()} YEARLY</div>
              <h2 className="text-5xl font-black">{currentDate.getMonth() + 1}월</h2>
            </div>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} className="p-3 hover:bg-white/10 rounded-2xl transition-all"><ChevronRight size={36} /></button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-6 -mt-20 space-y-10 relative z-20">
