            </div>
          </div>
          <div className="bg-white p-7 rounded-3xl shadow-xl border border-gray-100 group transition-all hover:translate-y-[-4px]">
            <div className="flex items-center gap-5">
              <div className="p-4 bg-red-50 text-red-600 rounded-2xl group-hover:bg-red-600 group-hover:text-white transition-colors"><TrendingDown size={30} /></div>
              <div><p className="text-xs font-bold text-gray-400 uppercase mb-1">총 지출</p><p className="text-2xl font-black text-gray-900">{stats.totalExpense.toLocaleString()}원</p></div>
            </div>
          </div>
          <div className="bg-white p-7 rounded-3xl shadow-xl border border-gray-100 group transition-all hover:translate-y-[-4px]">
