          </div>
          <div className="flex flex-wrap gap-3 justify-center">
            <button onClick={() => setIsHistoryOpen(true)} className="flex items-center gap-2 bg-white/5 hover:bg-white/15 px-4 py-2 rounded-xl text-xs font-bold border border-white/10 transition-all"><History size={16} />월간 리포트</button>
            <button onClick={() => setIsDataModalOpen(true)} className="flex items-center gap-2 bg-white/5 hover:bg-white/15 px-4 py-2 rounded-xl text-xs font-bold border border-white/10 transition-all"><Settings size={16} />데이터 관리</button>
            <button onClick={handleAnalyze} className="flex items-center gap-2 bg-indigo-500 hover:bg-indigo-400 px-5 py-2 rounded-xl text-xs font-black shadow-lg shadow-indigo-500/20 transition-all">
              {isAnalyzing ? <Loader2 className="animate-spin" size={16} /> : <Sparkles size={16} className="text-yellow-300" />}AI 분석 리포트
            </button>
          </div>
        </div>

        <div className="max-w-7xl mx-auto mt-12 flex flex-col items-center justify-center">
           <div className="flex items-center gap-8 md:gap-16">
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} className="p-3 hover:bg-white/10 rounded-full transition-all"><ChevronLeft size={36} /></button>
            <div className="text-center">
              <div className="text-indigo-300 text-sm font-bold mb-1">{currentDate.getFullYear()}</div>
              <h2 className="text-5xl font-black tracking-tight">{currentDate.getMonth() + 1}월</h2>
            </div>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} className="p-3 hover:bg-white/10 rounded-full transition-all"><ChevronRight size={36} /></button>
          </div>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="max-w-7xl mx-auto px-6 -mt-24 pb-20 relative z-20 space-y-8">
        {/* Quick Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {[
            { label: '총 수입', val: stats.totalIncome, color: 'blue', icon: <TrendingUp /> },
            { label: '총 지출', val: stats.totalExpense, color: 'red', icon: <TrendingDown /> },
            { label: '현재 잔액', val: stats.balance, color: stats.balance >= 0 ? 'emerald' : 'orange', icon: <Wallet /> }
          ].map((item, idx) => (
            <div key={idx} className="bg-white p-6 rounded-3xl shadow-xl border border-gray-100 flex items-center gap-5 hover:translate-y-[-4px] transition-transform">
              <div className={`p-4 bg-${item.color}-50 text-${item.color}-600 rounded-2xl`}>{item.icon}</div>
              <div>
                <p className="text-[10px] font-black text-gray-400 uppercase mb-1 tracking-wider">{item.label}</p>
                <p className="text-2xl font-black text-gray-900">{item.val.toLocaleString()}원</p>
              </div>
            </div>
          ))}
        </div>

        {showAnalysis && (
          <Card className="border-indigo-100 ring-8 ring-indigo-50/50 shadow-2xl" title="AI 정밀 재정 분석">
            {isAnalyzing ? (
              <div className="py-20 text-center flex flex-col items-center gap-4 text-gray-500">
                <Loader2 className="animate-spin text-indigo-500" size={40} />
                <p className="font-bold">데이터 분석 중...</p>
              </div>
            ) : <div className="prose prose-indigo max-w-none p-6 leading-relaxed whitespace-pre-line">{aiAnalysis}</div>}
          </Card>
        )}

        <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
          {/* Main Column */}
          <div className="xl:col-span-2 space-y-8">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <DashboardCharts currentMonthTransactions={filteredTransactions} />
                <YearlyChart transactions={transactions} year={currentDate.getFullYear()} />
                <div className="lg:col-span-2">
                  <InvestmentStatus records={investmentRecords} onAddRecord={(r) => setInvestmentRecords(prev => [...prev, { ...r, id: Math.random().toString(36).substr(2, 9) }])} onDeleteRecord={(id) => setInvestmentRecords(prev => prev.filter(r => r.id !== id))} currentViewDate={currentDate} />
                </div>
            </div>
            <BudgetOverview categories={expenseCats} transactions={filteredTransactions} budgets={budgets} onUpdateBudgets={setBudgets} />
          </div>

          {/* Sidebar Column */}
          <div className="space-y-8">
             <UpcomingBills expenses={recurringExpenses} onAdd={(e) => setRecurringExpenses(prev => [...prev, { ...e, id: Math.random().toString(36).substr(2, 9) }])} onUpdate={(u) => setRecurringExpenses(prev => prev.map(e => e.id === u.id ? u : e))} onDelete={(id) => setRecurringExpenses(prev => prev.filter(e => e.id !== id))} onPay={() => {}} currentViewDate={currentDate} transactions={transactions} categories={expenseCats} />

             <div id="transaction-form-section" className="bg-white rounded-3xl shadow-xl border border-gray-100 overflow-hidden">
                <div className={`px-8 py-5 border-b border-gray-100 ${editingTransaction ? 'bg-indigo-50' : 'bg-gray-50/50'}`}>
                  <h3 className="font-black text-gray-800 tracking-tighter uppercase">{editingTransaction ? '내역 수정' : '새 거래 입력'}</h3>
                </div>
                <div className="p-8">
                  <TransactionForm onAddTransaction={handleAddTransaction} onUpdateTransaction={handleUpdateTransaction} editingTransaction={editingTransaction} onCancelEdit={() => setEditingTransaction(null)} incomeCategories={incomeCats} expenseCategories={expenseCats} onOpenCategoryManager={() => setIsCategoryManagerOpen(true)} currentViewDate={currentDate} />
                </div>
             </div>

             <Card title="상세 내역 리스트" className="h-[600px] shadow-2xl border-indigo-50">
                <TransactionList 
                  transactions={transactions} 
                  currentViewDate={currentDate}
                  onDelete={handleDeleteTransaction}
                  onEdit={handleEditTransaction}
                />
             </Card>
          </div>
        </div>
      </main>

      {/* Modals & UI Components */}
      <CategoryManager isOpen={isCategoryManagerOpen} onClose={() => setIsCategoryManagerOpen(false)} incomeCategories={incomeCats} expenseCategories={expenseCats} onUpdateCategories={(type, newCats) => type === 'income' ? setIncomeCats(newCats) : setExpenseCats(newCats)} />
      <DataManagement isOpen={isDataModalOpen} onClose={() => setIsDataModalOpen(false)} transactions={transactions} onImport={handleImportData} onEmergencyRestore={() => {}} onExport={() => {}} />
      <MonthlyHistory isOpen={isHistoryOpen} onClose={() => setIsHistoryOpen(false)} transactions={transactions} onSelectMonth={setCurrentDate} />
      <ConfirmDialog isOpen={confirmDialog.isOpen} message={confirmDialog.message} onConfirm={confirmDialog.onConfirm} onClose={() => setConfirmDialog(prev => ({ ...prev, isOpen: false }))} />
      <InstallGuide isOpen={isInstallGuideOpen} onClose={() => setIsInstallGuideOpen(false)} deferredPrompt={deferredPrompt} onInstall={() => deferredPrompt?.prompt()} />
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Trash2, ArrowDownCircle, ArrowUpCircle, CreditCard, Edit2, Filter, ChevronDown } from 'lucide-react';
import { Transaction } from '../types';

interface Props {
  transactions: Transaction[];
  onDelete: (id: string) => void;
  onEdit: (transaction: Transaction) => void;
  currentViewDate: Date;
}

export const TransactionList: React.FC<Props> = ({ transactions, onDelete, onEdit, currentViewDate }) => {
  const [selectedYear, setSelectedYear] = useState<number>(currentViewDate ? currentViewDate.getFullYear() : new Date().getFullYear());
  const [selectedMonth, setSelectedMonth] = useState<number>(currentViewDate ? currentViewDate.getMonth() + 1 : new Date().getMonth() + 1);

  useEffect(() => {
    if (currentViewDate) {
      setSelectedYear(currentViewDate.getFullYear());
      setSelectedMonth(currentViewDate.getMonth() + 1);
    }
  }, [currentViewDate]);

  const availableYears = useMemo(() => {
    const years = new Set<number>([new Date().getFullYear()]);
    if (Array.isArray(transactions)) {
      transactions.forEach(t => {
        if (t.date) {
          const d = new Date(t.date);
          if (!isNaN(d.getTime())) {
            years.add(d.getFullYear());
          }
        }
      });
    }
    return Array.from(years).sort((a, b) => b - a);
  }, [transactions]);

  const filteredAndSortedTransactions = useMemo(() => {
    if (!Array.isArray(transactions)) return [];
    return transactions
      .filter(t => {
        if (!t.date) return false;
        const d = new Date(t.date);
        return d.getFullYear() === selectedYear && (d.getMonth() + 1) === selectedMonth;
      })
      .sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
  }, [transactions, selectedYear, selectedMonth]);

  const totalIncome = filteredAndSortedTransactions
    .filter(t => t.type === 'income')
    .reduce((sum, t) => sum + t.amount, 0);

  const totalExpense = filteredAndSortedTransactions
    .filter(t => t.type === 'expense')
    .reduce((sum, t) => sum + t.amount, 0);

  return (
    <div className="flex flex-col h-full overflow-hidden">
      {/* Filters Area */}
      <div className="p-4 bg-white border-b border-gray-50 shrink-0 z-10">
        <div className="flex items-center justify-between gap-3 mb-3">
          <div className="flex items-center gap-1.5">
            <div className="relative">
              <select
                value={selectedYear}
                onChange={(e) => setSelectedYear(Number(e.target.value))}
                className="appearance-none bg-gray-100 border-none text-gray-700 text-xs rounded-lg pl-3 pr-7 py-1.5 focus:ring-2 focus:ring-indigo-500 font-bold cursor-pointer"
              >
                {availableYears.map(year => (
                  <option key={year} value={year}>{year}년</option>
                ))}
              </select>
              <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
            </div>
            <div className="relative">
              <select
                value={selectedMonth}
                onChange={(e) => setSelectedMonth(Number(e.target.value))}
                className="appearance-none bg-gray-100 border-none text-gray-700 text-xs rounded-lg pl-3 pr-7 py-1.5 focus:ring-2 focus:ring-indigo-500 font-bold cursor-pointer"
              >
                {Array.from({ length: 12 }, (_, i) => i + 1).map(month => (
                  <option key={month} value={month}>{month}월</option>
                ))}
              </select>
              <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none" />
            </div>
          </div>
          <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
            {filteredAndSortedTransactions.length} RECORDS
          </div>
        </div>

        <div className="flex gap-2">
           <div className="px-3 py-1 bg-blue-50 text-blue-600 rounded-lg text-[10px] font-black uppercase">
             IN: {totalIncome.toLocaleString()}원
           </div>
           <div className="px-3 py-1 bg-red-50 text-red-600 rounded-lg text-[10px] font-black uppercase">
             OUT: {totalExpense.toLocaleString()}원
           </div>
        </div>
      </div>

      {/* List Container */}
      <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar scroll-smooth">
        {filteredAndSortedTransactions.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-gray-300">
            <Filter size={40} className="opacity-10 mb-2" />
            <p className="text-xs font-bold">내역이 없습니다.</p>
          </div>
        ) : (
          filteredAndSortedTransactions.map((t) => (
            <div key={t.id} className="group flex items-center justify-between p-4 bg-white border border-gray-100 rounded-2xl hover:shadow-lg hover:border-indigo-100 transition-all relative">
              <div className="flex items-center gap-4">
                <div className={`${t.type === 'income' ? 'text-blue-500' : 'text-red-500'} shrink-0`}>
                  {t.type === 'income' ? <ArrowUpCircle size={28} strokeWidth={2.5} /> : <ArrowDownCircle size={28} strokeWidth={2.5} />}
                </div>
                <div className="min-w-0">
                  <div className="flex items-center gap-2 mb-0.5">
                    <p className="font-bold text-gray-800 text-sm truncate">{t.category}</p>
                    {t.bank && (
                      <span className="text-[9px] px-1.5 py-0.5 bg-gray-50 text-gray-400 rounded-md border border-gray-100 flex items-center gap-1 shrink-0 font-bold uppercase">
                        <CreditCard size={10} />
                        {t.bank}
                      </span>
                    )}
                  </div>
                  <p className="text-[10px] text-gray-400 truncate font-medium">
                    {t.date} {t.description && `• ${t.description}`}
                  </p>
                </div>
              </div>
              <div className="flex items-center gap-4 shrink-0 ml-4">
                <span className={`font-black text-sm ${t.type === 'income' ? 'text-blue-600' : 'text-red-600'}`}>
                  {t.type === 'income' ? '+' : '-'}{t.amount.toLocaleString()}
                </span>

                <div className="flex items-center opacity-0 group-hover:opacity-100 transition-opacity">
                  <button 
                    onClick={() => onEdit(t)}
                    className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
                  >
                    <Edit2 size={16} />
                  </button>
                  <button 
                    onClick={() => onDelete(t.id)}
                    className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-colors"
                  >
                    <Trash2 size={16} />
                  </button>
                </div>
              </div>
            </div>
          ))
        )}
      </div>
      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: #e5e7eb; border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: #d1d5db; }
      `}</style>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ChevronLeft, ChevronRight, Wallet, TrendingUp, TrendingDown, 
  Sparkles, Loader2, History, Settings
} from 'lucide-react';
import { Transaction, MonthlyStats, EXPENSE_CATEGORIES, INCOME_CATEGORIES, BudgetMap, InvestmentRecord, RecurringExpense } from './types';
import { Card } from './components/ui/Card';
import { TransactionForm } from './components/TransactionForm';
import { TransactionList } from './components/TransactionList';
import { DashboardCharts } from './components/DashboardCharts';
import { YearlyChart } from './components/YearlyChart';
import { CategoryManager } from './components/CategoryManager';
import { DataManagement } from './components/DataManagement';
import { BudgetOverview } from './components/BudgetOverview';
import { MonthlyHistory } from './components/MonthlyHistory';
import { InvestmentStatus } from './components/InvestmentStatus';
import { UpcomingBills } from './components/UpcomingBills';
import { Toast } from './components/ui/Toast';
import { ConfirmDialog } from './components/ui/ConfirmDialog';
import { InstallGuide } from './components/InstallGuide';
import { analyzeFinancialData } from './services/geminiService';

const App = () => {
  // --- State Management ---
  const [currentDate, setCurrentDate] = useState(new Date());
  const [isStorageReady, setIsStorageReady] = useState(false);
  const [isPersistent, setIsPersistent] = useState(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isInstallGuideOpen, setIsInstallGuideOpen] = useState(false);

  // Strict initializers to avoid undefined references
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    try {
      const saved = localStorage.getItem('moneyflow_transactions');
      if (!saved) return [];
      const parsed = JSON.parse(saved);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      console.error("Storage load error:", e);
      return [];
    }
  });

  const [investmentRecords, setInvestmentRecords] = useState<InvestmentRecord[]>(() => {
    try {
      const saved = localStorage.getItem('moneyflow_investments');
      return saved ? JSON.parse(saved) : [];
    } catch(e) { return []; }
  });

  const [recurringExpenses, setRecurringExpenses] = useState<RecurringExpense[]>(() => {
    try {
      const saved = localStorage.getItem('moneyflow_recurring_bills');
      return saved ? JSON.parse(saved) : [];
    } catch(e) { return []; }
  });

  const [expenseCats, setExpenseCats] = useState<string[]>(() => {
    const saved = localStorage.getItem('moneyflow_expense_categories_v3');
    return saved ? JSON.parse(saved) : EXPENSE_CATEGORIES;
  });

  const [incomeCats, setIncomeCats] = useState<string[]>(() => {
    const saved = localStorage.getItem('moneyflow_income_categories_v3');
    return saved ? JSON.parse(saved) : INCOME_CATEGORIES;
  });

  const [budgets, setBudgets] = useState<BudgetMap>(() => {
    const saved = localStorage.getItem('moneyflow_budgets');
    return saved ? JSON.parse(saved) : {};
  });

  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [isDataModalOpen, setIsDataModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [toast, setToast] = useState<{ msg: string; type?: 'success'|'error'|'info' } | null>(null);
  const [confirmDialog, setConfirmDialog] = useState<{ isOpen: boolean; message: string; onConfirm: () => void }>({
    isOpen: false, message: '', onConfirm: () => {},
  });

  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);

  // --- Persistence Hooks ---
  useEffect(() => {
    setIsStorageReady(true);
    if (navigator.storage && navigator.storage.persist) {
      navigator.storage.persist().then(granted => setIsPersistent(granted));
    }
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  useEffect(() => {
    if (isStorageReady) localStorage.setItem('moneyflow_transactions', JSON.stringify(transactions));
  }, [transactions, isStorageReady]);

  useEffect(() => {
    if (isStorageReady) localStorage.setItem('moneyflow_investments', JSON.stringify(investmentRecords));
  }, [investmentRecords, isStorageReady]);

  useEffect(() => {
    if (isStorageReady) localStorage.setItem('moneyflow_recurring_bills', JSON.stringify(recurringExpenses));
  }, [recurringExpenses, isStorageReady]);

  useEffect(() => {
    localStorage.setItem('moneyflow_expense_categories_v3', JSON.stringify(expenseCats));
  }, [expenseCats]);

  useEffect(() => {
    localStorage.setItem('moneyflow_income_categories_v3', JSON.stringify(incomeCats));
  }, [incomeCats]);

  useEffect(() => {
    localStorage.setItem('moneyflow_budgets', JSON.stringify(budgets));
  }, [budgets]);

  // --- Computed Stats ---
  const currentMonthStr = useMemo(() => {
    if (!currentDate) return new Date().toISOString().slice(0, 7);
    const offset = currentDate.getTimezoneOffset() * 60000;
    return new Date(currentDate.getTime() - offset).toISOString().slice(0, 7);
  }, [currentDate]);

  const filteredTransactions = useMemo(() => {
    if (!Array.isArray(transactions)) return [];
    return transactions.filter(t => t.date && t.date.startsWith(currentMonthStr));
  }, [transactions, currentMonthStr]);

  const stats: MonthlyStats = useMemo(() => {
    return filteredTransactions.reduce((acc, curr) => {
      if (curr.type === 'income') {
        acc.totalIncome += curr.amount;
        acc.balance += curr.amount;
      } else {
        acc.totalExpense += curr.amount;
        acc.balance -= curr.amount;
      }
      return acc;
    }, { totalIncome: 0, totalExpense: 0, balance: 0 });
  }, [filteredTransactions]);

  const showToast = (msg: string, type: 'success'|'error'|'info' = 'success') => setToast({ msg, type });

  // --- Handlers ---
  const handleAddTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const tx: Transaction = { ...newTx, id: Math.random().toString(36).substr(2, 9) };
    setTransactions(prev => [...prev, tx]);
    showToast('내역이 성공적으로 추가되었습니다.');
  };

  const handleEditTransaction = (tx: Transaction) => {
    setEditingTransaction(tx);
    const element = document.getElementById('transaction-form-section');
    if (element) element.scrollIntoView({ behavior: 'smooth', block: 'center' });
  };

  const handleUpdateTransaction = (updatedTx: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updatedTx.id ? updatedTx : t));
    setEditingTransaction(null);
    showToast('내역이 수정되었습니다.');
  };

  const handleDeleteTransaction = (id: string) => {
    setConfirmDialog({
        isOpen: true,
        message: '이 거래 내역을 정말 삭제하시겠습니까? 삭제 후에는 복구할 수 없습니다.',
        onConfirm: () => {
            setTransactions(prev => prev.filter(t => t.id !== id));
            showToast('내역이 삭제되었습니다.', 'info');
        }
    });
  };

  const handleAnalyze = async () => {
    const yearTransactions = transactions.filter(t => t.date && new Date(t.date).getFullYear() === currentDate.getFullYear());
    if (yearTransactions.length === 0) {
      showToast('분석할 데이터가 부족합니다.', 'error');
      return;
    }
    setIsAnalyzing(true);
    setShowAnalysis(true);
    const result = await analyzeFinancialData(yearTransactions, `${currentDate.getFullYear()}년 ${currentDate.getMonth() + 1}월`);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  const handleImportData = (importedData: any) => {
    if (Array.isArray(importedData)) {
      setTransactions(importedData);
    } else if (importedData && typeof importedData === 'object') {
      if (Array.isArray(importedData.transactions)) setTransactions(importedData.transactions);
      if (importedData.budgets) setBudgets(importedData.budgets);
      if (importedData.investmentRecords) setInvestmentRecords(importedData.investmentRecords);
      if (importedData.recurringExpenses) setRecurringExpenses(importedData.recurringExpenses);
    } else {
      showToast('올바른 데이터 형식이 아닙니다.', 'error');
      return;
    }
    showToast('데이터 복구가 완료되었습니다.');
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-900 flex flex-col">
      {/* Dynamic Header */}
      <header className="bg-indigo-900 text-white pt-8 pb-32 px-6 shadow-2xl relative">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-white/10 rounded-2xl border border-white/20 shadow-inner">
              <Wallet size={32} />
            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tight">MoneyFlow AI</h1>
              <p className="text-indigo-300 text-[10px] font-bold uppercase tracking-widest">
                {isPersistent ? 'PERSISTENT' : 'LOCAL'} STORAGE ACTIVE
              </p>
            </div>
          </div>
          <div className="flex flex-wrap gap-3 justify-center">
            <button onClick={() => setIsHistoryOpen(true)} className="flex items-center gap-2 bg-white/5 hover:bg-white/15 px-4 py-2 rounded-xl text-xs font-bold border border-white/10 transition-all"><History size={16} />기록 조회</button>
            <button onClick={() => setIsDataModalOpen(true)} className="flex items-center gap-2 bg-white/5 hover:bg-white/15 px-4 py-2 rounded-xl text-xs font-bold border border-white/10 transition-all"><Settings size={16} />백업/복구</button>
            <button onClick={handleAnalyze} className="flex items-center gap-2 bg-indigo-500 hover:bg-indigo-400 px-5 py-2 rounded-xl text-xs font-black shadow-lg shadow-indigo-500/30 transition-all active:scale-95">
              {isAnalyzing ? <Loader2 className="animate-spin" size={16} /> : <Sparkles size={16} className="text-yellow-300" />}AI 분석
            </button>
