}

export default {
  plugins: {
    tailwindcss: {},
    autoprefixer: {},
  },
}

import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  define: {
    'process.env': {
      API_KEY: JSON.stringify(process.env.API_KEY)
    }
  },
  server: {
    port: 3000
  },
  build: {
    outDir: 'dist',
    sourcemap: false
  }
});

import React, { useState, useEffect, useMemo } from 'react';
import { 
  ChevronLeft, ChevronRight, Wallet, TrendingUp, TrendingDown, 
  Sparkles, Loader2, History, Settings, Smartphone
} from 'lucide-react';
import { Transaction, MonthlyStats, EXPENSE_CATEGORIES, INCOME_CATEGORIES, BudgetMap, InvestmentRecord, RecurringExpense, BackupData } from './types';
import { Card } from './components/ui/Card';
import { TransactionForm } from './components/TransactionForm';
import { TransactionList } from './components/TransactionList';
import { DashboardCharts } from './components/DashboardCharts';
import { YearlyChart } from './components/YearlyChart';
import { CategoryManager } from './components/CategoryManager';
import { DataManagement } from './components/DataManagement';
import { BudgetOverview } from './components/BudgetOverview';
import { MonthlyHistory } from './components/MonthlyHistory';
import { InvestmentStatus } from './components/InvestmentStatus';
import { UpcomingBills } from './components/UpcomingBills';
import { Toast } from './components/ui/Toast';
import { ConfirmDialog } from './components/ui/ConfirmDialog';
import { InstallGuide } from './components/InstallGuide';
import { analyzeFinancialData } from './services/geminiService';

const App = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [isStorageReady, setIsStorageReady] = useState(false);
  const [isPersistent, setIsPersistent] = useState(false);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isInstallGuideOpen, setIsInstallGuideOpen] = useState(false);

  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    try {
      const saved = localStorage.getItem('moneyflow_transactions');
      return saved ? JSON.parse(saved) : [];
    } catch (e) { return []; }
  });

  const [investmentRecords, setInvestmentRecords] = useState<InvestmentRecord[]>(() => {
    try {
      const saved = localStorage.getItem('moneyflow_investments');
      return saved ? JSON.parse(saved) : [];
    } catch(e) { return []; }
  });

  const [recurringExpenses, setRecurringExpenses] = useState<RecurringExpense[]>(() => {
    try {
      const saved = localStorage.getItem('moneyflow_recurring_bills');
      return saved ? JSON.parse(saved) : [];
    } catch(e) { return []; }
  });

  const [expenseCats, setExpenseCats] = useState<string[]>(() => {
    const saved = localStorage.getItem('moneyflow_expense_categories_v3');
    return saved ? JSON.parse(saved) : EXPENSE_CATEGORIES;
  });

  const [incomeCats, setIncomeCats] = useState<string[]>(() => {
    const saved = localStorage.getItem('moneyflow_income_categories_v3');
    return saved ? JSON.parse(saved) : INCOME_CATEGORIES;
  });

  const [budgets, setBudgets] = useState<BudgetMap>(() => {
    const saved = localStorage.getItem('moneyflow_budgets');
    return saved ? JSON.parse(saved) : {};
  });

  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [isCategoryManagerOpen, setIsCategoryManagerOpen] = useState(false);
  const [isDataModalOpen, setIsDataModalOpen] = useState(false);
  const [isHistoryOpen, setIsHistoryOpen] = useState(false);
  const [toast, setToast] = useState<{ msg: string; type?: 'success'|'error'|'info' } | null>(null);
  const [confirmDialog, setConfirmDialog] = useState<{ isOpen: boolean; message: string; onConfirm: () => void }>({
    isOpen: false, message: '', onConfirm: () => {},
  });

  const [aiAnalysis, setAiAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [showAnalysis, setShowAnalysis] = useState(false);

  useEffect(() => {
    setIsStorageReady(true);
    if (navigator.storage && navigator.storage.persist) {
      navigator.storage.persist().then(granted => setIsPersistent(granted));
    }
    const handleBeforeInstallPrompt = (e: any) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    return () => window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
  }, []);

  useEffect(() => { if (isStorageReady) localStorage.setItem('moneyflow_transactions', JSON.stringify(transactions)); }, [transactions, isStorageReady]);
  useEffect(() => { if (isStorageReady) localStorage.setItem('moneyflow_investments', JSON.stringify(investmentRecords)); }, [investmentRecords, isStorageReady]);
  useEffect(() => { if (isStorageReady) localStorage.setItem('moneyflow_recurring_bills', JSON.stringify(recurringExpenses)); }, [recurringExpenses, isStorageReady]);
  useEffect(() => { localStorage.setItem('moneyflow_expense_categories_v3', JSON.stringify(expenseCats)); }, [expenseCats]);
  useEffect(() => { localStorage.setItem('moneyflow_income_categories_v3', JSON.stringify(incomeCats)); }, [incomeCats]);
  useEffect(() => { localStorage.setItem('moneyflow_budgets', JSON.stringify(budgets)); }, [budgets]);

  const currentMonthStr = useMemo(() => {
    const y = currentDate.getFullYear();
    const m = String(currentDate.getMonth() + 1).padStart(2, '0');
    return `${y}-${m}`;
  }, [currentDate]);

  const filteredTransactions = useMemo(() => {
    return transactions.filter(t => t.date && t.date.startsWith(currentMonthStr));
  }, [transactions, currentMonthStr]);

  const stats: MonthlyStats = useMemo(() => {
    return filteredTransactions.reduce((acc, curr) => {
      if (curr.type === 'income') {
        acc.totalIncome += curr.amount;
        acc.balance += curr.amount;
      } else {
        acc.totalExpense += curr.amount;
        acc.balance -= curr.amount;
      }
      return acc;
    }, { totalIncome: 0, totalExpense: 0, balance: 0 });
  }, [filteredTransactions]);

  const showToast = (msg: string, type: 'success'|'error'|'info' = 'success') => setToast({ msg, type });

  const handleAddTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const tx: Transaction = { ...newTx, id: Math.random().toString(36).substr(2, 9) };
    setTransactions(prev => [...prev, tx]);
    showToast('기록이 추가되었습니다.');
  };

  const handleEditTransaction = (tx: Transaction) => {
    setEditingTransaction(tx);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleUpdateTransaction = (updatedTx: Transaction) => {
    setTransactions(prev => prev.map(t => t.id === updatedTx.id ? updatedTx : t));
    setEditingTransaction(null);
    showToast('기록이 수정되었습니다.');
  };

  const handleDeleteTransaction = (id: string) => {
    setConfirmDialog({
        isOpen: true,
        message: '이 내역을 정말 삭제하시겠습니까?',
        onConfirm: () => {
            setTransactions(prev => prev.filter(t => t.id !== id));
            showToast('내역이 삭제되었습니다.', 'info');
        }
    });
  };

  const handlePayBill = (bill: RecurringExpense) => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    const day = Math.min(bill.day, new Date(year, month + 1, 0).getDate());
    const dateStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;

    handleAddTransaction({
      date: dateStr,
      amount: bill.amount,
      type: 'expense',
      category: bill.category || '기타',
      bank: '현금',
      description: bill.name
    });
    showToast(`'${bill.name}' 지출 처리가 완료되었습니다.`);
  };

  const handleAnalyze = async () => {
    const yearTransactions = transactions.filter(t => t.date && new Date(t.date).getFullYear() === currentDate.getFullYear());
    if (yearTransactions.length === 0) {
      showToast('분석할 데이터가 없습니다.', 'error');
      return;
    }
    setIsAnalyzing(true);
    setShowAnalysis(true);
    const result = await analyzeFinancialData(yearTransactions, `${currentDate.getFullYear()}년 ${currentDate.getMonth() + 1}월`);
    setAiAnalysis(result);
    setIsAnalyzing(false);
  };

  const handleExportData = () => {
    const data: BackupData = { transactions, recurringExpenses, investmentRecords, budgets, expenseCategories: expenseCats, incomeCategories: incomeCats };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `moneyflow_backup_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
    showToast('백업 파일이 생성되었습니다.');
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 flex flex-col pb-20">
      <header className="bg-indigo-700 text-white pt-10 pb-36 px-6 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -translate-y-1/2 translate-x-1/2 blur-3xl"></div>
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6 relative z-10">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-white/20 rounded-2xl backdrop-blur-md border border-white/30 shadow-xl">
              <Wallet size={32} />
            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tight">MoneyFlow AI</h1>
              <div className="flex items-center gap-2">
                <span className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse"></span>
                <p className="text-indigo-200 text-[10px] font-bold uppercase tracking-widest">System Online</p>
              </div>
            </div>
          </div>
          <div className="flex flex-wrap gap-2 justify-center">
            <button onClick={() => setIsHistoryOpen(true)} className="flex items-center gap-2 bg-white/10 hover:bg-white/20 px-4 py-2 rounded-xl text-xs font-bold border border-white/10 transition-all"><History size={16} />기록</button>
            <button onClick={() => setIsDataModalOpen(true)} className="flex items-center gap-2 bg-white/10 hover:bg-white/20 px-4 py-2 rounded-xl text-xs font-bold border border-white/10 transition-all"><Settings size={16} />설정</button>
            <button onClick={() => setIsInstallGuideOpen(true)} className="flex items-center gap-2 bg-white/10 hover:bg-white/20 px-4 py-2 rounded-xl text-xs font-bold border border-white/10 transition-all"><Smartphone size={16} />설치</button>
            <button onClick={handleAnalyze} className="flex items-center gap-2 bg-indigo-400 hover:bg-indigo-300 px-5 py-2 rounded-xl text-xs font-black shadow-lg transition-all active:scale-95">
              {isAnalyzing ? <Loader2 className="animate-spin" size={16} /> : <Sparkles size={16} className="text-yellow-200" />}AI 분석
            </button>
          </div>
        </div>

        <div className="max-w-7xl mx-auto mt-12 flex flex-col items-center justify-center relative z-10">
           <div className="flex items-center gap-8 md:gap-16">
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1))} className="p-3 hover:bg-white/10 rounded-full transition-all active:bg-white/20"><ChevronLeft size={36} /></button>
            <div className="text-center">
              <div className="text-indigo-200 text-sm font-bold mb-1 tracking-widest">{currentDate.getFullYear()}</div>
              <h2 className="text-5xl font-black tracking-tight">{currentDate.getMonth() + 1}월</h2>
            </div>
            <button onClick={() => setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1))} className="p-3 hover:bg-white/10 rounded-full transition-all active:bg-white/20"><ChevronRight size={36} /></button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto w-full px-6 -mt-24 space-y-8 relative z-20">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <Card className="bg-white p-6 border-none shadow-xl flex items-center gap-5 hover:translate-y-[-4px] transition-all duration-300">
            <div className="p-4 bg-blue-50 text-blue-600 rounded-2xl"><TrendingUp size={28} /></div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase mb-1">총 수입</p>
              <p className="text-2xl font-black text-slate-900">{stats.totalIncome.toLocaleString()}원</p>
            </div>
          </Card>
          <Card className="bg-white p-6 border-none shadow-xl flex items-center gap-5 hover:translate-y-[-4px] transition-all duration-300">
            <div className="p-4 bg-red-50 text-red-600 rounded-2xl"><TrendingDown size={28} /></div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase mb-1">총 지출</p>
              <p className="text-2xl font-black text-slate-900">{stats.totalExpense.toLocaleString()}원</p>
            </div>
          </Card>
          <Card className="bg-white p-6 border-none shadow-xl flex items-center gap-5 hover:translate-y-[-4px] transition-all duration-300">
            <div className={`p-4 rounded-2xl ${stats.balance >= 0 ? 'bg-emerald-50 text-emerald-600' : 'bg-orange-50 text-orange-600'}`}><Wallet size={28} /></div>
            <div>
              <p className="text-[10px] font-black text-slate-400 uppercase mb-1">이달의 잔고</p>
              <p className={`text-2xl font-black ${stats.balance >= 0 ? 'text-slate-900' : 'text-red-600'}`}>{stats.balance.toLocaleString()}원</p>
            </div>
          </Card>
        </div>

        {showAnalysis && (
          <Card className="border-indigo-100 ring-4 ring-indigo-50 shadow-2xl overflow-hidden" title="AI 스마트 재정 리포트">
            {isAnalyzing ? (
              <div className="py-20 text-center flex flex-col items-center gap-4 text-slate-500">
                <Loader2 className="animate-spin text-indigo-500" size={48} />
                <p className="font-bold">Gemini AI가 가계부를 심층 분석하고 있습니다...</p>
              </div>
            ) : <div className="p-8 prose prose-indigo max-w-none leading-relaxed whitespace-pre-line text-slate-700 bg-gradient-to-b from-white to-indigo-50/20">{aiAnalysis}</div>}
          </Card>
        )}

        <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
          <div className="xl:col-span-2 space-y-8">
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                <DashboardCharts currentMonthTransactions={filteredTransactions} />
                <YearlyChart transactions={transactions} year={currentDate.getFullYear()} />
                <div className="lg:col-span-2">
                  <InvestmentStatus records={investmentRecords} onAddRecord={(r) => setInvestmentRecords(prev => [...prev, { ...r, id: Math.random().toString(36).substr(2, 9) }])} onDeleteRecord={(id) => setInvestmentRecords(prev => prev.filter(r => r.id !== id))} currentViewDate={currentDate} />
                </div>
            </div>
            <BudgetOverview categories={expenseCats} transactions={filteredTransactions} budgets={budgets} onUpdateBudgets={setBudgets} />
          </div>

          <div className="space-y-8">
             <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden">
                <div className={`px-8 py-5 border-b border-slate-100 ${editingTransaction ? 'bg-amber-50' : 'bg-slate-50/50'}`}>
                  <h3 className="font-black text-slate-800 tracking-tighter uppercase">{editingTransaction ? '거래 정보 수정 중' : '새 거래 기록'}</h3>
                </div>
                <div className="p-8">
                  <TransactionForm onAddTransaction={handleAddTransaction} onUpdateTransaction={handleUpdateTransaction} editingTransaction={editingTransaction} onCancelEdit={() => setEditingTransaction(null)} incomeCategories={incomeCats} expenseCategories={expenseCats} onOpenCategoryManager={() => setIsCategoryManagerOpen(true)} currentViewDate={currentDate} />
                </div>
             </div>

             <UpcomingBills 
                expenses={recurringExpenses} 
                onAdd={(e) => setRecurringExpenses(prev => [...prev, { ...e, id: Math.random().toString(36).substr(2, 9) }])} 
                onUpdate={(u) => setRecurringExpenses(prev => prev.map(e => e.id === u.id ? u : e))} 
                onDelete={(id) => setRecurringExpenses(prev => prev.filter(e => e.id !== id))} 
                onPay={handlePayBill} 
                currentViewDate={currentDate} 
                transactions={transactions} 
                categories={expenseCats} 
             />

             <Card title="상세 내역 리스트" className="h-[600px] shadow-2xl">
                <TransactionList transactions={transactions} currentViewDate={currentDate} onDelete={handleDeleteTransaction} onEdit={handleEditTransaction} />
             </Card>
          </div>
        </div>
      </main>

      <CategoryManager isOpen={isCategoryManagerOpen} onClose={() => setIsCategoryManagerOpen(false)} incomeCategories={incomeCats} expenseCategories={expenseCats} onUpdateCategories={(type, newCats) => type === 'income' ? setIncomeCats(newCats) : setExpenseCats(newCats)} />
      <DataManagement isOpen={isDataModalOpen} onClose={() => setIsDataModalOpen(false)} transactions={transactions} onImport={(d) => { if(Array.isArray(d)) setTransactions(d); else if(d.transactions) setTransactions(d.transactions); showToast('복구 완료'); }} onEmergencyRestore={() => { const s = localStorage.getItem('moneyflow_transactions'); if(s) setTransactions(JSON.parse(s)); }} onExport={handleExportData} />
      <MonthlyHistory isOpen={isHistoryOpen} onClose={() => setIsHistoryOpen(false)} transactions={transactions} onSelectMonth={setCurrentDate} />
      <ConfirmDialog isOpen={confirmDialog.isOpen} message={confirmDialog.message} onConfirm={confirmDialog.onConfirm} onClose={() => setConfirmDialog(prev => ({ ...prev, isOpen: false }))} />
      <InstallGuide isOpen={isInstallGuideOpen} onClose={() => setIsInstallGuideOpen(false)} deferredPrompt={deferredPrompt} onInstall={() => deferredPrompt?.prompt()} />
      {toast && <Toast message={toast.msg} type={toast.type} onClose={() => setToast(null)} />}
    </div>
  );
};

